import React, { useEffect, useRef, memo } from 'react';
import Chart from 'chart.js/auto';
import styled from 'styled-components';

const ChartContainer = styled.div`
  width: 100%;
  height: 100%;
  position: relative;
  canvas {
    width: 100% !important;
    height: 100% !important;
  }
`;

const LineChart = memo(({ data, height = 400, showLegend = true, showAxes = true, unit = 'number', horizontalLabels = false, reducedLabels = false, type }) => {
  const chartRef = useRef(null);
  const chartInstance = useRef(null);

  // Handle unit from type or unitType prop for backward compatibility
  const unitType = unit || (type === 'area' ? 'currency' : 'number');

  useEffect(() => {
    // Only proceed if we have valid data
    if (!data || !data.labels || !data.datasets || data.datasets.length === 0) {
      console.error("Invalid chart data provided:", data);
      return;
    }

    // Make sure all datasets have data
    data.datasets.forEach((dataset, index) => {
      // Ensure each dataset has visible points
      dataset.pointRadius = dataset.pointRadius || 4;
      dataset.pointHoverRadius = dataset.pointHoverRadius || 6;
      
      if (!dataset.data || dataset.data.length === 0) {
        console.warn(`Dataset ${index} has no data`);
      }
    });

    // Destroy existing chart if it exists
    if (chartInstance.current) {
      chartInstance.current.destroy();
    }

    // Log what we're going to render
    console.log("Rendering chart with data:", data);

    // Get the context of the canvas element
    const ctx = chartRef.current.getContext('2d');
    
    // Set chart type and fill based on type prop
    let chartType = 'line';
    let fill = false;
    
    if (type === 'area') {
      chartType = 'line';
      fill = true;
    } else if (type === 'donut') {
      chartType = 'doughnut';
    }

    // Format ticks based on unit type
    const formatNumber = (value) => {
      if (value === null || value === undefined) return '';
      if (value >= 1000000) {
        return (value / 1000000).toFixed(1) + 'M';
      } else if (value >= 1000) {
        return (value / 1000).toFixed(1) + 'K';
      }
      return value.toFixed(0);
    };

    const formatCurrency = (value) => {
      if (value === null || value === undefined) return '';
      if (value >= 1000000) {
        return '$' + (value / 1000000).toFixed(1) + 'M';
      } else if (value >= 1000) {
        return '$' + (value / 1000).toFixed(1) + 'K';
      }
      return '$' + value.toFixed(0);
    };

    const formatPercentage = (value) => {
      if (value === null || value === undefined) return '';
      return value.toFixed(2) + '%';
    };
    
    // Basic configuration options with reduced animation duration
    const options = {
      responsive: true,
      maintainAspectRatio: false,
      animation: {
        duration: 300, // Reduced animation time to prevent flickering
      },
      interaction: {
        mode: 'index',
        intersect: false,
      },
      plugins: {
        legend: {
          display: showLegend,
          position: 'top',
          labels: {
            usePointStyle: true,
            boxWidth: 6,
            font: {
              size: 12,
            },
          },
        },
        tooltip: {
          enabled: true,
          callbacks: {
            label: function(context) {
              let label = context.dataset.label || '';
              if (label) {
                label += ': ';
              }
              if (unitType === 'currency') {
                label += formatCurrency(context.parsed.y);
              } else if (unitType === 'percentage') {
                label += formatPercentage(context.parsed.y);
              } else {
                label += formatNumber(context.parsed.y);
              }
              return label;
            }
          }
        },
      },
      scales: {
        x: {
          display: showAxes,
          grid: {
            display: showAxes,
            color: '#eee',
          },
          ticks: {
            font: {
              size: 11,
            },
            color: '#999',
            rotation: horizontalLabels ? 0 : -45,
            callback: reducedLabels ? function(value, index, ticks) {
              if (ticks.length <= 2) return data.labels[index];
              
              if (ticks.length > 10) {
                if (index === 0 || index === ticks.length - 1 || index % Math.floor(ticks.length / 3) === 0) {
                  return data.labels[index];
                }
                return '';
              }
              
              if (index === 0 || index === ticks.length - 1 || index % 2 === 0) {
                return data.labels[index];
              }
              return '';
            } : undefined
          }
        },
        y: {
          display: showAxes,
          grid: {
            display: showAxes,
            color: '#eee',
          },
          ticks: {
            font: {
              size: 11,
            },
            color: '#999',
            callback: function(value) {
              if (unitType === 'currency') {
                return formatCurrency(value);
              } else if (unitType === 'percentage') {
                return formatPercentage(value);
              } else if (unitType === 'days') {
                return value + (value === 1 ? ' day' : ' days');
              } else {
                return formatNumber(value);
              }
            },
            suggestedMin: 0
          }
        }
      }
    };
    
    // Add specific options based on chart type
    if (chartType === 'line') {
      options.scales = {
        x: {
          grid: {
            display: false
          },
          ticks: {
            font: {
              family: "'Inter', sans-serif",
              size: 11
            }
          }
        },
        y: {
          beginAtZero: unitType !== 'percentage',
          grid: {
            color: 'rgba(0, 0, 0, 0.05)'
          },
          ticks: {
            font: {
              family: "'Inter', sans-serif",
              size: 11
            },
            callback: function(value) {
              if (unitType === 'currency') {
                return formatCurrency(value);
              } else if (unitType === 'percentage') {
                return formatPercentage(value);
              } else {
                return formatNumber(value);
              }
            }
          }
        }
      };
      
      // For area charts, modify the dataset
      if (fill) {
        data.datasets.forEach(dataset => {
          dataset.fill = true;
          dataset.backgroundColor = dataset.borderColor ? `${dataset.borderColor}15` : 'rgba(75, 192, 192, 0.2)';
        });
      }
    } else if (chartType === 'bar') {
      options.scales = {
        x: {
          grid: {
            display: false
          },
          ticks: {
            font: {
              family: "'Inter', sans-serif",
              size: 11
            }
          }
        },
        y: {
          beginAtZero: unitType !== 'percentage',
          grid: {
            color: 'rgba(0, 0, 0, 0.05)'
          },
          ticks: {
            font: {
              family: "'Inter', sans-serif",
              size: 11
            },
            callback: function(value) {
              if (unitType === 'currency') {
                return formatCurrency(value);
              } else if (unitType === 'percentage') {
                return formatPercentage(value);
              } else {
                return formatNumber(value);
              }
            }
          }
        }
      };
    } else if (chartType === 'pie' || chartType === 'doughnut') {
      // Pie and doughnut charts don't need scales
      delete options.scales;
      
      // Add cutout percentage for doughnut
      if (chartType === 'doughnut') {
        options.cutout = '60%';
      }
    }

    // Create the chart
    try {
      chartInstance.current = new Chart(ctx, {
        type: chartType,
        data: data,
        options: {
          ...options,
          elements: {
            line: {
              tension: 0.4 // Smooth lines
            },
            point: {
              radius: 4, // Ensure points are visible
              hoverRadius: 6,
              hitRadius: 10
            }
          }
        }
      });
    } catch (error) {
      console.error("Error creating chart:", error);
    }
    
    // Cleanup function to destroy chart on unmount
    return () => {
      if (chartInstance.current) {
        chartInstance.current.destroy();
      }
    };
  }, [data, height, showLegend, unitType, type, showAxes, horizontalLabels, reducedLabels]);

  return (
    <ChartContainer style={{ height: `${height}px` }}>
      <canvas ref={chartRef}></canvas>
    </ChartContainer>
  );
}, (prevProps, nextProps) => {
  // Implement custom comparison for memoization
  // Only re-render if essential props changed
  return (
    JSON.stringify(prevProps.data) === JSON.stringify(nextProps.data) &&
    prevProps.height === nextProps.height &&
    prevProps.showLegend === nextProps.showLegend &&
    prevProps.unit === nextProps.unit &&
    prevProps.type === nextProps.type
  );
});

export default LineChart; 